import{c as s,Q as a,j as e,m as l}from"./chunks/framework.DVkeSyfh.js";const k=JSON.parse('{"title":"Скрипт восстановления аудиометаданных","description":"","frontmatter":{},"headers":[],"relativePath":"ru/scripts/repair-audio-metadata.md","filePath":"ru/scripts/repair-audio-metadata.md","lastUpdated":1780017229000}'),d={name:"ru/scripts/repair-audio-metadata.md"};function t(p,i,o,c,n,r){return a(),e("div",null,[...i[0]||(i[0]=[l(`<h1 id="скрипт-восстановления-аудиометаданных" tabindex="-1">Скрипт восстановления аудиометаданных <a class="header-anchor" href="#скрипт-восстановления-аудиометаданных" aria-label="Permalink to &quot;Скрипт восстановления аудиометаданных&quot;">​</a></h1><p>Запускайте этот скрипт по возможности из окружения Python проекта:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">help</span></span></code></pre></div><p>Отдельный вспомогательный инструмент для диагностики и восстановления проблем с аудиометаданными и контейнерами. Сухой прогон (dry-run) работает только на чтение и не копирует и не записывает аудиофайлы.</p><p>Используйте этот скрипт, когда сканирование, обновление тегов или запись жанров сообщают о подозрительных или нечитаемых метаданных, особенно в краевых случаях с WAV/AIFF и контейнерами. Не применяйте его как обычный редактор тегов: это инструмент диагностики и восстановления для файлов, которые скрипт классифицирует как безопасные для ремонта.</p><p>Использование:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python scripts\\audio_repair\\repair_audio_metadata.py [OPTIONS] [paths ...]</span></span></code></pre></div><p>Входные данные:</p><ul><li>позиционные <code>paths</code>: аудиофайлы для проверки или восстановления.</li><li><code>--folder FOLDER</code>: рекурсивно собрать поддерживаемые аудиофайлы из папки.</li><li><code>--db DB</code>: собрать существующие аудиофайлы из <code>tracks.path</code> в базе данных библиотеки SQLite. База данных открывается только на чтение.</li><li><code>--db-root PATH</code>: использовать только пути базы данных под этим сохранённым корнем. Можно указывать несколько раз.</li><li><code>--file-root PATH</code>: заменить соответствующий префикс <code>--db-root</code> этим реальным корнем файловой системы перед проверкой существования каждого файла.</li><li><code>--log LOG</code>: извлечь из лога проекта пути к WAV-файлам, у которых после сохранения не прошла повторная проверка чтения.</li><li><code>--since TIMESTAMP</code>: использовать только строки лога с указанной временной метки и позже.</li><li><code>--until TIMESTAMP</code>: использовать только строки лога до указанной временной метки.</li></ul><p>Параметры восстановления и безопасности:</p><ul><li><code>--apply</code>: записать восстановленные файлы. По умолчанию — dry-run.</li><li><code>--backup-dir PATH</code>: каталог резервных копий, используется только с <code>--apply</code>.</li><li><code>--no-backup</code>: применить изменения без полных резервных копий файлов; используйте только если уже существует другая резервная копия.</li><li><code>--keep-id3 first|last|none</code>: при восстановлении WAV выбрать, какой читаемый ID3-чанк верхнего уровня сохранить. По умолчанию — <code>first</code>.</li><li><code>--reason VALUE</code>: в режиме папки или базы данных применять изменения только к записям с сохранённой причиной. Можно указывать несколько раз.</li></ul><p>Управление запуском:</p><ul><li><code>--limit N</code>: обработать только первые собранные пути.</li><li><code>--summary-only</code>: вывести только итоговую сводку.</li><li><code>--color auto|always|never</code>: подсвечивать метки статусов цветом.</li><li><code>--file-log PATH</code>: путь к файловому логу, перезаписываемому при каждом запуске.</li><li><code>--no-file-log</code>: отключить файловый лог.</li><li><code>--state PATH</code>: явный файл состояния для режима папки или базы данных.</li><li><code>--workers N</code>: число параллельных воркеров для dry-run. Режим применения всегда выполняется последовательно.</li></ul><p>Рекомендуемый порядок:</p><ol><li>Запустите dry-run на небольшом наборе путей, папке, логе или подмножестве базы данных.</li><li>Просмотрите статус и причину для каждой записи <code>REPAIRABLE</code>.</li><li>Запускайте <code>--apply</code> только для той причины или набора файлов, которые вы намерены исправить.</li><li>Оставляйте резервные копии включёнными, если у вас уже нет внешней резервной копии.</li></ol><p>Примеры:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">folder .\\music </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">workers </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">folder .\\music </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">apply </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">reason OVERSIZED_DATA</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db C:\\db\\abstracted.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root M:\\Volumes\\Abstracted</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db C:\\db\\abstracted.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root M:\\Volumes </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">file</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root S:\\Music\\Volumes</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py .\\music\\track.wav </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">summary</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">only</span></span></code></pre></div><p>Значения статусов:</p><ul><li><code>OK</code>: восстановление не требуется.</li><li><code>NOTICE</code>: косметическая, необязательная очистка; файл не перезаписывается.</li><li><code>REPAIRABLE</code>: безопасное восстановление существует (dry-run только сообщает о нём).</li><li><code>REPAIRED</code>: режим применения записал проверенное восстановление.</li><li><code>SUSPICIOUS</code>: несоответствие формата/контейнера или кодека, требующее более внимательной проверки.</li><li><code>TAG-ERROR</code>: ошибка чтения тега без безопасного пути восстановления.</li><li><code>BROKEN</code>: файл не удалось разобрать как ожидаемый контейнер.</li><li><code>FAILED</code>: в режиме применения восстановление было предпринято, но его не удалось записать или проверить.</li><li><code>UNSUPPORTED</code>: расширение вне восстанавливаемого набора WAV/AIFF; только проверка.</li></ul><p>Причины:</p><p>В режиме папки или базы данных каждый результат также записывает причину в верхнем регистре. Используйте её с <code>--reason</code>, чтобы повторно запустить применение только для одного класса исправлений, например:</p><ul><li><code>OVERSIZED_DATA</code>: WAV-чанк <code>data</code> больше, чем полезная аудионагрузка до ID3.</li><li><code>DUPLICATE_ID3</code>: более одного ID3-чанка верхнего уровня в WAV.</li><li><code>EMPTY_ID3</code>: пустой AIFF-чанк <code>ID3 </code>, блокирующий чтение Mutagen.</li><li><code>CONTAINER_NORMALIZATION</code>: нормализация корневого размера или выравнивания RIFF/FORM.</li><li><code>EXTENSION_MISMATCH</code>: контейнер/кодек не соответствует расширению файла.</li></ul><p><code>--reason</code> допустим только в режиме папки или базы данных (он требует файла состояния). Указывайте точный текст причины, показанный в отчёте.</p><p>Коды выхода:</p><ul><li><code>0</code>: завершено без результатов <code>FAILED</code>.</li><li><code>1</code>: хотя бы один файл завершился со статусом <code>FAILED</code>.</li><li><code>2</code>: ошибка использования, например <code>--file-root</code> без <code>--db-root</code>, <code>--reason</code> вне режима состояния, <code>--backup-dir</code> вместе с <code>--no-backup</code> или не найдено ни одного входного пути.</li></ul>`,25)])])}const E=s(d,[["render",t]]);export{k as __pageData,E as default};
